function count_ways(symbols, ops) {
    const n = symbols.length;
    const T = Array.from({length:n}, () => new Array(n).fill(0));
    const F = Array.from({length:n}, () => new Array(n).fill(0));
    for (let i=0;i<n;i++) { if (symbols[i]==='T') T[i][i]=1; else F[i][i]=1; }
    for (let len=2;len<=n;len++) {
        for (let i=0;i+len-1<n;i++) {
            const j=i+len-1;
            for (let k=i;k<j;k++) {
                const op=ops[k];
                const lt=T[i][k], lf=F[i][k], rt=T[k+1][j], rf=F[k+1][j];
                const total=(lt+lf)*(rt+rf);
                let trueWays;
                if (op==='&') trueWays = lt*rt;
                else if (op==='|') trueWays = total - lf*rf;
                else trueWays = lt*rf + lf*rt;
                T[i][j]+=trueWays; F[i][j]+=(total-trueWays);
            }
        }
    }
    return T[0][n-1];
}

function combination_sum_count(candidates, target) {
    const dp = new Array(target+1).fill(0); dp[0]=1;
    for (const c of candidates) for (let i=c;i<=target;i++) dp[i]+=dp[i-c];
    return dp[target];
}

function delete_and_earn(nums) {
    if (nums.length===0) return 0;
    const maxV = Math.max(...nums); const bucket = new Array(maxV+1).fill(0);
    for (const x of nums) bucket[x]+=x;
    let prev=0, cur=0;
    for (let v=0;v<=maxV;v++) { const t=Math.max(cur, prev+bucket[v]); prev=cur; cur=t; }
    return cur;
}

function find_min(nums) {
    let lo=0, hi=nums.length-1;
    while (lo<hi) { const mid=(lo+hi)>>1; if (nums[mid]>nums[hi]) lo=mid+1; else hi=mid; }
    return nums[lo];
}

function group_anagrams_count(strs) {
    const seen = new Set();
    for (const s of strs) { const key = s.split('').sort().join(''); seen.add(key); }
    return seen.size;
}

function job_scheduling(deadlines, profits) {
    const n = deadlines.length;
    const idx = Array.from({length:n}, (_,i)=>i).sort((a,b)=>profits[b]-profits[a]);
    const maxD = Math.max(...deadlines);
    const slot = new Array(maxD+1).fill(false);
    let total = 0;
    for (const i of idx) {
        for (let d=Math.min(deadlines[i], maxD); d>=1; d--) {
            if (!slot[d]) { slot[d]=true; total+=profits[i]; break; }
        }
    }
    return total;
}

function last_occurrence(nums, target) {
    let lo=0, hi=nums.length-1, ans=-1;
    while (lo<=hi) {
        const mid=(lo+hi)>>1;
        if (nums[mid]===target) { ans=mid; lo=mid+1; }
        else if (nums[mid]<target) lo=mid+1; else hi=mid-1;
    }
    return ans;
}

function character_replacement(s, k) {
    const freq={}; let left=0, maxCount=0, best=0;
    for (let right=0;right<s.length;right++) {
        const ch=s[right]; freq[ch]=(freq[ch]||0)+1;
        maxCount=Math.max(maxCount, freq[ch]);
        while (right-left+1-maxCount>k) { freq[s[left]]--; left++; }
        best=Math.max(best, right-left+1);
    }
    return best;
}

function majority_element_ii(nums) {
    let c1=null, c2=null, cnt1=0, cnt2=0;
    for (const x of nums) {
        if (c1===x) cnt1++;
        else if (c2===x) cnt2++;
        else if (cnt1===0) { c1=x; cnt1=1; }
        else if (cnt2===0) { c2=x; cnt2=1; }
        else { cnt1--; cnt2--; }
    }
    cnt1=0; cnt2=0;
    for (const x of nums) { if (x===c1) cnt1++; else if (x===c2) cnt2++; }
    const out=[];
    if (cnt1>Math.floor(nums.length/3)) out.push(c1);
    if (cnt2>Math.floor(nums.length/3)) out.push(c2);
    out.sort((a,b)=>a-b);
    return out;
}

function find_max_xor(nums) {
    let best=0;
    for (let i=0;i<nums.length;i++) for (let j=i+1;j<nums.length;j++) {
        const x=nums[i]^nums[j]; if (x>best) best=x;
    }
    return best;
}

function min_subarray_len(nums, target) {
    let left=0, sum=0, best=Infinity;
    for (let right=0;right<nums.length;right++) {
        sum+=nums[right];
        while (sum>=target) { best=Math.min(best, right-left+1); sum-=nums[left]; left++; }
    }
    const r = best===Infinity?0:best;
    return r===0?r:r;
}

function next_greater_element(nums) {
    const n = nums.length; const out = new Array(n).fill(-1); const stack = [];
    for (let i=0;i<n;i++) {
        while (stack.length && nums[stack[stack.length-1]] < nums[i]) { out[stack.pop()] = nums[i]; }
        stack.push(i);
    }
    return out;
}

function count_partitions(s) {
    const n=s.length;
    const isPal = Array.from({length:n}, () => new Array(n).fill(false));
    for (let i=0;i<n;i++) isPal[i][i]=true;
    for (let len=2;len<=n;len++) {
        for (let i=0;i+len-1<n;i++) {
            const j=i+len-1;
            if (s[i]===s[j] && (len===2 || isPal[i+1][j-1])) isPal[i][j]=true;
        }
    }
    const dp=new Array(n+1).fill(0); dp[0]=1;
    for (let i=1;i<=n;i++) {
        for (let j=0;j<i;j++) { if (isPal[j][i-1]) dp[i]+=dp[j]; }
    }
    return dp[n];
}

function remove_nth_from_end(values, k) {
    const n=values.length; const idx=n-k;
    const out=[...values.slice(0,idx), ...values.slice(idx+1)];
