function ship_within_days(weights, days) {
    function daysNeeded(cap) {
        let d=1, cur=0;
        for (const w of weights) { if (cur+w>cap) { d++; cur=w; } else cur+=w; }
        return d;
    }
    let lo=Math.max(...weights), hi=weights.reduce((a,b)=>a+b,0);
    while (lo<hi) { const mid=Math.floor((lo+hi)/2); if (daysNeeded(mid)<=days) hi=mid; else lo=mid+1; }
    return lo;
}

function subarrays_div_by_k(nums, k) {
    const seen = new Array(k).fill(0); seen[0]=1;
    let sum=0, count=0;
    for (const x of nums) { sum += x; let mod=((sum%k)+k)%k; count += seen[mod]; seen[mod]++; }
    return count;
}

function trap(heights) {
    let lo=0, hi=heights.length-1, leftMax=0, rightMax=0, total=0;
    while (lo<hi) {
        if (heights[lo] < heights[hi]) {
            leftMax = Math.max(leftMax, heights[lo]); total += leftMax - heights[lo]; lo++;
        } else { rightMax = Math.max(rightMax, heights[hi]); total += rightMax - heights[hi]; hi--; }
    }
    return total;
}

function is_valid_palindrome(s) {
    const clean = s.toLowerCase().replace(/[^a-z0-9]/g, '');
    let lo = 0, hi = clean.length - 1;
    while (lo < hi) { if (clean[lo] !== clean[hi]) return false; lo++; hi--; }
    return true;
}
